.darma-loader-darma-custom-411 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #5eead4);
  width: 40px;
  aspect-ratio: 1;
  border-radius: 50%;
  color: var(--loader-color, #0f766e);
  border: 2px solid;
  box-sizing: border-box;
  position: relative;
  transform-origin: left;
  animation: darma-loader-darma-custom-411-l2 1s infinite linear;
}.darma-loader-darma-custom-411::before,.darma-loader-darma-custom-411::after {content: "";
  position: absolute;
  inset: 0 0 auto;
  margin: auto;
  width: 50%;
  aspect-ratio: 1;
  border-radius: 50%;
  border: 2px solid;
  box-sizing: content-box;
  transform-origin: 50% calc(100% - 4px);
  animation: inherit;
}.darma-loader-darma-custom-411::after {inset:auto 0 calc(100% + 2px);
  animation-duration: 0.5s;
  animation-direction: reverse;
  transform-origin: 50% calc(200% - 2px);
}@keyframes darma-loader-darma-custom-411-l2{100% {transform: rotate(1turn)}}

